import{_ as o,C as c,o as a,c as r,a2 as d,E as l}from"./chunks/framework.C90q7Ucc.js";const g=JSON.parse('{"title":"流式卡片","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/streaming-card.md","filePath":"architecture/streaming-card.md","lastUpdated":1780678956000}'),i={name:"architecture/streaming-card.md"};function s(n,e,u,h,p,m){const t=c("MermaidDiagram");return a(),r("div",null,[e[0]||(e[0]=d('<h1 id="流式卡片" tabindex="-1">流式卡片 <a class="header-anchor" href="#流式卡片" aria-label="Permalink to &quot;流式卡片&quot;">​</a></h1><p>飞书的流式卡片功能非常强大，其丰富的前端效果组合是 CodeLark 能够实现精美交互的关键。使用中，有时会遇到流失卡片更新加载不及时，或者弱网环境下卡片更新较慢的情况。为此引入了大量面向用户体验和性能的优化、埋点分析。本文说明 CodeLark 把 runtime 输出投递到飞书流式卡片的完整链路及响应机制的模块归属。</p><blockquote><p>飞书文档：</p><ul><li><a href="https://open.feishu.cn/document/feishu-cards/card-json-v2-components/content-components/rich-text" target="_blank" rel="noreferrer">富文本</a></li><li><a href="https://open.feishu.cn/document/feishu-cards/card-json-v2-components/content-components/title" target="_blank" rel="noreferrer">标题</a></li><li><a href="https://open.feishu.cn/document/feishu-cards/card-json-v2-components/containers/form-container" target="_blank" rel="noreferrer">表单容器</a></li><li><a href="https://open.feishu.cn/document/feishu-cards/card-json-v2-components/containers/collapsible-panel" target="_blank" rel="noreferrer">折叠面板</a></li></ul></blockquote><h2 id="总览" tabindex="-1">总览 <a class="header-anchor" href="#总览" aria-label="Permalink to &quot;总览&quot;">​</a></h2>',4)),l(t,{code64:""}),e[1]||(e[1]=d(`<p>核心原则：</p><ul><li>runtime、mirror、工具进度、任务进度和状态文本只改本地 desired state。</li><li><code>scheduleCardFlush()</code> 负责把细碎变化合并到下一轮 flush。</li><li><code>flushCardUpdate()</code> 在 flush 时读取一份 desired snapshot，和本地 shadow 比较后生成投递计划。</li><li>只有投递计划执行器能调用飞书 CardKit API。</li><li>本地 shadow 表示“飞书服务端接受过什么”，不表示“用户客户端已经完成重绘”。</li></ul><h2 id="生命周期" tabindex="-1">生命周期 <a class="header-anchor" href="#生命周期" aria-label="Permalink to &quot;生命周期&quot;">​</a></h2><h3 id="首屏创建" tabindex="-1">首屏创建 <a class="header-anchor" href="#首屏创建" aria-label="Permalink to &quot;首屏创建&quot;">​</a></h3><p>入口是 <code>FeishuAdapter.createStreamingCard()</code>，实际创建在 <code>_doCreateStreamingCard()</code>。</p><ol><li>用当前正文、任务、状态、工具、actions 和 metadata 渲染初始 CardKit JSON，日志为 <code>Streaming card create payload</code>。</li><li>调用 <code>cardkit.v1.card.create</code> 创建 CardKit 卡片，payload 是 <code>{ type: &quot;card_json&quot;, data: &lt;card json&gt; }</code>。</li><li>把返回的 <code>card_id</code> 包成 interactive 消息内容。</li><li>如果是回复已有消息，调用 <code>im.message.reply</code>；否则调用 <code>im.message.create</code>，消息类型都是 <code>interactive</code>。</li><li>把 <code>cardId</code>、<code>messageId</code>、sequence、desired 字段、rendered 字段和 perf 统计写入 <code>activeCards</code>。</li></ol><p>需要观察：</p><ul><li><code>card.create</code> 耗时、超时次数、payload bytes、component count。</li><li><code>im.message.*:interactive</code> 耗时和超时次数。</li><li>从 <code>onMessageStart</code> 到 card message id 可见的首屏耗时。</li></ul><h3 id="流式更新" tabindex="-1">流式更新 <a class="header-anchor" href="#流式更新" aria-label="Permalink to &quot;流式更新&quot;">​</a></h3><p>运行中的入口包括：</p><ul><li><code>updateCardContent()</code>：正文。</li><li><code>updateCardStatus()</code>：状态和 context usage。</li><li><code>updateToolProgress()</code>：工具面板。</li><li><code>updateTaskProgress()</code>：任务列表。</li><li><code>updateStreamingHistory()</code>：history-driven transcript。</li><li><code>updateCardMetadata()</code>：runtime/model/bridge 标签。</li><li><code>updateCardActions()</code>：按钮和表单 actions。</li></ul><p>这些函数只更新 desired 字段，递增 <code>desiredRevision</code>，然后调用 <code>scheduleCardFlush()</code>。真正远端请求在 <code>flushCardUpdate()</code> 中执行。</p><p>调度规则：</p><ul><li>同一张卡同时只允许一个 <code>flushInFlight</code> 或 <code>backgroundFlushInFlight</code>。</li><li>请求进行中又有新状态到来，只设置 <code>flushQueued=true</code>。</li><li>成功后下一次最早 flush 间隔默认 2s。</li><li>第一次失败后最早间隔默认 5s。</li><li>多次失败后封顶默认 10s。</li><li>单个飞书请求默认 timeout 为 15s。</li></ul><p>需要观察：</p><ul><li>每个 stream 的 flush attempt 数、成功数、失败数、timeout 数。</li><li>每次 flush 的 plan：<code>noop</code>、<code>batchUpdate</code>、<code>fullRefresh</code>。</li><li><code>flushQueued</code> 发生次数，表示请求期间又有新状态进来。</li><li>每次 flush 从 schedule 到发起、从发起到结束的耗时。</li></ul><h3 id="增量更新" tabindex="-1">增量更新 <a class="header-anchor" href="#增量更新" aria-label="Permalink to &quot;增量更新&quot;">​</a></h3><p>flush 阶段分四步：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>snapshotStreamingDesiredState(state)</span></span>
<span class="line"><span>  -&gt; buildDesiredRenderSnapshot(state, snapshot)</span></span>
<span class="line"><span>  -&gt; planStreamingSync(state, desiredRender)</span></span>
<span class="line"><span>  -&gt; executeStreamingSyncPlan(...) 或 flushFullCardRefresh(...)</span></span></code></pre></div><p><code>planStreamingSync()</code> 只产出三类计划：</p><table tabindex="0"><thead><tr><th>计划</th><th>触发条件</th><th>投递方式</th></tr></thead><tbody><tr><td><code>noop</code></td><td>desired 和 shadow 已一致</td><td>不调用飞书 API</td></tr><tr><td><code>batchUpdate</code></td><td>只有可证明安全的局部差异</td><td><code>cardElement.content</code>、<code>cardElement.create</code>、<code>cardElement.patch</code> 或 <code>card.batchUpdate</code></td></tr><tr><td><code>fullRefresh</code></td><td>shadow 不可信、metadata/action/layout 变化、history/tool 结构风险、周期性校正、小卡片直接刷新或用户文本边界更新</td><td><code>card.update</code> 写整张卡</td></tr></tbody></table><p><code>executeStreamingSyncPlan()</code> 可能调用：</p><ul><li><code>card.batchUpdate</code>：批量 create/patch 元素。</li><li><code>cardElement.create</code>：追加元素。</li><li><code>cardElement.patch</code>：局部 patch 元素。</li><li><code>cardElement.content</code>：更新单个元素内容，常见目标是 <code>streaming_content</code>、<code>streaming_tasks</code>、<code>streaming_status</code>。</li></ul><p>需要观察：</p><ul><li>按 target 分组的耗时：<code>streaming_content</code>、<code>streaming_tasks</code>、<code>streaming_status</code>、tool/history element。</li><li><code>cardElement.content:streaming_status</code> 的频率和耗时，判断状态刷新是否占用预算。</li><li><code>batchUpdate</code> 的 action count、payload bytes、耗时。</li><li><code>patch</code> 是否导致 <code>shadowTrust=weak</code>，以及随后是否触发 full refresh。</li></ul><h3 id="full-refresh" tabindex="-1">Full Refresh <a class="header-anchor" href="#full-refresh" aria-label="Permalink to &quot;Full Refresh&quot;">​</a></h3><p>入口是 <code>flushFullCardRefresh()</code>，底层调用 <code>card.update:streaming_refresh</code> 更新整张卡 JSON。Full refresh 通常比单 element update 更重，但在 shadow 不可信或结构变化时更可靠。</p><p>常见触发条件：</p><ul><li><code>shadowTrust !== &quot;trusted&quot;</code>，例如 timeout、失败、慢 batch 或 patch 后进入 <code>shadow_unknown</code> / <code>shadow_weak</code>。</li><li>actions、metadata、正文 layout signature 或 history signature 变化。</li><li>history/tool append 需要 full refresh。</li><li>用户文本边界更新走 <code>direct_refresh_user_text</code>。</li><li>小卡片里如果本来要形成 batch，优先 <code>direct_refresh_small_card</code>。</li><li>非 historyDriven 卡片周期性 refresh。</li></ul><p>需要观察：</p><ul><li>fullRefresh 次数和原因：<code>shadow_unknown</code>、<code>shadow_weak</code>、<code>direct_refresh_user_text</code>、<code>direct_refresh_small_card</code>、<code>periodic_refresh</code> 等。</li><li>full refresh payload bytes、component count、耗时、超时次数。</li><li>full refresh 后是否立即又有 <code>flushQueued</code>，表示刷新期间新状态继续堆积。</li></ul><h3 id="finalize" tabindex="-1">Finalize <a class="header-anchor" href="#finalize" aria-label="Permalink to &quot;Finalize&quot;">​</a></h3><p>入口是 <code>finalizeCard()</code>。</p><ol><li>等待已有 flush 完成，等待时间是请求超时加一个额外缓冲。</li><li>调用 <code>card.settings</code>，写入 <code>{ streaming_mode: false }</code>，sequence 递增。</li><li>渲染最终卡片 JSON，包括最终正文、任务、工具、footer、actions 和 metadata。</li><li>如果组件数超过上限，裁剪较早 history/tool 内容。</li><li>调用 <code>card.update</code> 写最终卡。</li><li>成功后按 completed/error 添加终态 reaction。</li></ol><p>需要观察：</p><ul><li>finalize 前等待 flush 的耗时和是否超时。</li><li><code>card.settings</code> 耗时。</li><li>final <code>card.update</code> payload bytes、component count、耗时。</li><li>background finalize 触发次数：<code>Streaming card finalize exceeded blocking budget</code>。</li></ul><h2 id="卡片结构" tabindex="-1">卡片结构 <a class="header-anchor" href="#卡片结构" aria-label="Permalink to &quot;卡片结构&quot;">​</a></h2><p>流式卡片按“稳定分区 + 局部元素 ID”组织，目标是让 adapter 能用 diff 决定低成本局部更新，必要时回退到 full refresh。</p><table tabindex="0"><thead><tr><th>分区</th><th>主要元素 ID</th><th>数据来源</th><th>正常更新方式</th><th>失效时回退</th></tr></thead><tbody><tr><td>Header</td><td>header title、<code>streaming_tag_*</code></td><td>stream metadata、runtime/model/bridge 标签</td><td>metadata 变化触发 <code>card.update</code> full refresh</td><td>关闭流式后 final <code>card.update</code></td></tr><tr><td>Metadata body tags</td><td><code>streaming_tag_*</code></td><td>stream metadata tags</td><td>full refresh</td><td>final <code>card.update</code></td></tr><tr><td>History / 正文容器</td><td><code>stream_history</code></td><td><code>historyItems</code> 或正文 + tools</td><td>追加 markdown/tool panel 子元素</td><td>full refresh 或续接新卡片</td></tr><tr><td>正文 markdown</td><td><code>streaming_content</code></td><td><code>pendingText</code></td><td><code>cardElement.content</code></td><td>full refresh</td></tr><tr><td>工具面板</td><td><code>stream_tool_N</code> / 子事件元素</td><td><code>toolCalls</code> 或 history tool panel</td><td>create/append；工具结构变化倾向 full refresh</td><td>full refresh 或续接新卡片</td></tr><tr><td>任务区</td><td><code>streaming_tasks</code></td><td>task progress</td><td><code>cardElement.content</code></td><td>full refresh</td></tr><tr><td>状态区</td><td><code>streaming_status</code></td><td>elapsed/status/context usage</td><td><code>cardElement.content</code></td><td>final status append 或 full refresh</td></tr><tr><td>Actions</td><td>action rows</td><td>stream actions</td><td>full refresh</td><td>关闭流式后 final <code>card.update</code></td></tr></tbody></table><p>这个分区不是 CardKit 原生概念，是 CodeLark adapter 的同步边界。<code>renderedHistoryElementJson</code>、<code>renderedToolSnapshots</code>、<code>renderedComponentCount</code> 等状态只表示“本地认为已经提交到飞书服务端的结构”，不能证明用户客户端已经完成重绘。</p><h2 id="本地镜像" tabindex="-1">本地镜像 <a class="header-anchor" href="#本地镜像" aria-label="Permalink to &quot;本地镜像&quot;">​</a></h2><p>创建后的 <code>FeishuCardState</code> 同时保存两类状态：</p><table tabindex="0"><thead><tr><th>类型</th><th>代表字段</th><th>含义</th></tr></thead><tbody><tr><td>Desired state</td><td><code>pendingText</code>、<code>pendingTasksText</code>、<code>pendingStatusText</code>、<code>toolCalls</code>、<code>historyItems</code>、<code>metadata</code>、<code>actionRows</code>、<code>desiredRevision</code></td><td>本地现在希望卡片长什么样</td></tr><tr><td>Remote shadow</td><td><code>renderedText</code>、<code>renderedTasksText</code>、<code>renderedStatusText</code>、<code>renderedHistoryElementIds</code>、<code>renderedHistoryElementJson</code>、<code>renderedToolSnapshots</code>、<code>rendered*Signature</code>、<code>renderedComponentCount</code>、<code>shadowRevision</code>、<code>shadowTrust</code></td><td>本地认为已经被飞书服务端接受的卡片状态</td></tr></tbody></table><p>Remote shadow 不是从飞书客户端反查出来的真实 DOM，而是 CodeLark 在每次 API 成功后提交的本地账本：</p><ul><li><code>cardElement.content</code> 成功后，只更新对应 element 的 rendered 内容。</li><li><code>cardElement.create</code> / <code>patch</code> / <code>card.batchUpdate</code> 成功后，更新对应 history/tool element 的快照。</li><li><code>card.update</code> full refresh 成功后，用完整 desired render 覆盖 shadow。</li><li>慢 batch 或 patch 成功后，<code>shadowTrust</code> 会降级为 <code>weak</code>，下一轮优先整卡校正。</li><li>失败或 timeout 会把 shadow 视为不可信，后续投递倾向 full refresh。</li></ul><p>这层 shadow 的价值是抑制重复投递：如果 desired snapshot 和 shadow 已一致，planner 直接返回 <code>noop</code>。</p><h2 id="抑制碎片投递" tabindex="-1">抑制碎片投递 <a class="header-anchor" href="#抑制碎片投递" aria-label="Permalink to &quot;抑制碎片投递&quot;">​</a></h2><p>CodeLark 不会让每个 mirror record 都触发一次远端请求。抑制碎片投递靠三层机制完成。</p><p>第一层是 desired 覆盖写。正文、任务、状态、工具和 history 事件到来时只覆盖本地最新状态；flush 还没发生时，中间态自然被合并。</p><p>第二层是 per-card flush gate。同一张卡同时只允许一个 <code>flushInFlight</code> 或 <code>backgroundFlushInFlight</code>。请求进行中又来了新状态，只设置 <code>flushQueued=true</code>，当前请求结束后再排下一轮。</p><p>第三层是拥塞窗口。成功后下一轮最早 flush 间隔使用基础间隔；失败后进入第一次失败间隔，再进入最大失败间隔。飞书请求默认也有超时保护，timeout 会进入失败路径。</p><p>这个设计牺牲了逐事件可见性，换来三个稳定性收益：</p><ul><li>远端 API 频率受控。</li><li>飞书客户端弱网或慢刷新时，不会堆积大量过期更新。</li><li>每轮投递都基于最新 desired snapshot，而不是 replay 一串已经过时的事件。</li></ul><h2 id="打字机模式" tabindex="-1">打字机模式 <a class="header-anchor" href="#打字机模式" aria-label="Permalink to &quot;打字机模式&quot;">​</a></h2><p>CardKit 的 <code>streaming_mode</code> 只影响文本流式上屏的表现，不应成为卡片内容可靠同步的前提。CodeLark 当前的主要用户可见内容集中在正文区和工具区，各区域都允许用 full refresh 或最终普通卡片更新：</p><ul><li>正文区：不强制流式。可以用 <code>cardElement.content</code> 更新固定 <code>streaming_content</code> 元素，也可以用 <code>card.update</code> / full refresh 直接写入全文。</li><li>状态区：不需要严格流式。<code>streaming_status</code> 可以用 <code>cardElement.content</code> 低频更新；如果结构变化或客户端不同步，可以接受 full refresh。</li><li>任务区：不需要严格流式。<code>streaming_tasks</code> 可以低频更新；多任务结构变化可以接受 full refresh。</li><li>工具区：不需要严格流式。工具调用面板、长输出折叠面板和 history/tool panel 追加不应依赖高频 <code>batchUpdate</code> 保证每个中间态都上屏。</li><li>header、tag、actions、按钮、表单：不需要流式。运行中可以低频 full refresh；最终交互组件应在关闭流式后再更新。</li></ul><p>飞书文档中的 <code>streaming_config.print_frequency_ms</code>、<code>print_step</code>、<code>print_strategy</code> 控制的是流式更新文本的打字机上屏，不控制 <code>batchUpdate</code> 组件树同步。因此不要把 <code>batchUpdate</code> 当成正文流式刷新机制。</p><h2 id="长连接刷新" tabindex="-1">长连接刷新 <a class="header-anchor" href="#长连接刷新" aria-label="Permalink to &quot;长连接刷新&quot;">​</a></h2><p>飞书侧的长连接负责把用户消息、云文档评论、群生命周期和卡片交互回调推到本地 bridge。CodeLark 订阅的关键事件和回调包括：</p><ul><li><code>im.message.receive_v1</code>：IM 消息入口。</li><li><code>drive.notice.comment_add_v1</code>：云文档评论入口。</li><li><code>im.chat.member.bot.deleted_v1</code>：bot 被移出群。</li><li><code>im.chat.disbanded_v1</code>：群被解散。</li><li><code>card.action.trigger</code>：卡片按钮、表单和交互动作。</li></ul><p>长连接刷新和流式卡片刷新是两条不同链路：</p><ul><li>长连接刷新解决“飞书事件如何到达本地 bridge”。</li><li>CardKit 刷新解决“本地 bridge 如何把 stream UI 状态写回飞书卡片”。</li></ul><p>如果长连接断开，bridge 收不到新的用户输入或按钮回调；如果 CardKit 刷新失败，bridge 仍可能继续执行 runtime，但用户看到的卡片会停留在旧状态。排障时需要分别看 WebSocket/事件日志和 <code>perf.card.sync_plan</code>、<code>cardElement.*</code>、<code>card.update:*</code> 日志。</p><h2 id="续接与组件上限" tabindex="-1">续接与组件上限 <a class="header-anchor" href="#续接与组件上限" aria-label="Permalink to &quot;续接与组件上限&quot;">​</a></h2><p>飞书流式卡片有 200 个组件的限制，当前 adapter 使用 <code>STREAMING_CARD_COMPONENT_LIMIT=160</code> 作为软上限。运行中会用 <code>countFeishuCardComponents</code> 估算当前完整渲染和增量更新后的组件数。</p><p>接近或超过上限时，优先执行续接：</p><ol><li>对旧卡调用 <code>card.settings</code> 关闭 <code>streaming_mode</code>。</li><li>尝试用 <code>cardElement.content</code> 把旧卡状态区改成“已续接到下一条”。</li><li>用相同 stream key 创建 continuation card。</li><li>continuation card 从 <code>historyItemOffset</code> 或 <code>toolCallOffset</code> 后继续渲染。</li><li>如果续接失败，再尝试 <code>card.update</code> full refresh。</li></ol><p>续接依赖 shadow 中记录的已渲染 history/tool offset。由于 shadow 不是客户端 ACK，慢 batch 或弱确认场景下要保守降级，避免 offset 跳过用户没看到的内容。</p><h2 id="底层飞书-api" tabindex="-1">底层飞书 API <a class="header-anchor" href="#底层飞书-api" aria-label="Permalink to &quot;底层飞书 API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>SDK 调用</th><th>关键参数</th><th>用途</th></tr></thead><tbody><tr><td>创建 CardKit 卡</td><td><code>cardkit.v1.card.create</code></td><td><code>data.type=&quot;card_json&quot;</code>、<code>data.data=&lt;card json&gt;</code></td><td>在 CardKit 创建可复用卡片，获得 <code>card_id</code></td></tr><tr><td>发送卡片消息</td><td><code>im.message.reply</code></td><td><code>msg_type=&quot;interactive&quot;</code>、<code>content={&quot;type&quot;:&quot;card&quot;,&quot;data&quot;:{&quot;card_id&quot;:...}}</code></td><td>回复已有 IM 消息</td></tr><tr><td>发送卡片消息</td><td><code>im.message.create</code></td><td><code>receive_id_type=&quot;chat_id&quot;</code>、<code>msg_type=&quot;interactive&quot;</code>、<code>content={&quot;type&quot;:&quot;card&quot;,&quot;data&quot;:{&quot;card_id&quot;:...}}</code></td><td>主动向 chat 发送卡片</td></tr><tr><td>更新固定文本区</td><td><code>cardkit.v1.cardElement.content</code></td><td><code>card_id</code>、<code>element_id</code>、<code>content</code>、<code>sequence</code></td><td>更新正文、任务、状态等固定 element</td></tr><tr><td>追加元素</td><td><code>cardkit.v1.cardElement.create</code></td><td><code>card_id</code>、<code>type=&quot;append&quot;</code>、<code>target_element_id</code>、<code>elements</code>、<code>sequence</code></td><td>追加 history/tool 子元素</td></tr><tr><td>局部 patch</td><td><code>cardkit.v1.cardElement.patch</code></td><td><code>card_id</code>、<code>element_id</code>、<code>partial_element</code>、<code>sequence</code></td><td>更新工具面板等结构的一部分</td></tr><tr><td>批量更新</td><td><code>cardkit.v1.card.batchUpdate</code></td><td><code>actions</code>、<code>sequence</code></td><td>合并 <code>add_elements</code> 和 <code>partial_update_element</code></td></tr><tr><td>整卡刷新</td><td><code>cardkit.v1.card.update</code></td><td><code>card={type:&quot;card_json&quot;,data:&lt;card json&gt;}</code>、<code>sequence</code></td><td>full refresh 或最终定稿</td></tr><tr><td>关闭流式</td><td><code>cardkit.v1.card.settings</code></td><td><code>settings={&quot;streaming_mode&quot;:false}</code>、<code>sequence</code></td><td>定稿或续接前关闭 streaming mode</td></tr><tr><td>终态 reaction</td><td><code>im.messageReaction.create</code></td><td><code>message_id</code>、emoji type</td><td>completed/error 结果提示</td></tr></tbody></table><p>所有 CardKit 更新都依赖递增的 <code>sequence</code>。关闭 streaming mode 本身也占用一个 sequence，因此 finalize 和 rollover 都会在 <code>card.settings</code> 后继续递增 sequence 再更新卡片。</p><h2 id="日志与性能观测" tabindex="-1">日志与性能观测 <a class="header-anchor" href="#日志与性能观测" aria-label="Permalink to &quot;日志与性能观测&quot;">​</a></h2><p>已经有的日志：</p><ul><li><code>Request start/success/timeout/error</code>：所有 <code>withFeishuRequestTimeout()</code> 包裹的飞书 API 请求。</li><li><code>Streaming card create payload</code>：首屏卡片 payload 摘要。</li><li><code>Streaming sync plan</code>：每次 flush 的计划类型和原因。</li><li><code>Streaming card full refresh payload</code>：full refresh payload 摘要。</li><li><code>Final card update payload</code>：最终卡 payload 摘要。</li><li><code>cardElement.* failed</code>、<code>card.update streaming refresh failed</code>：更新失败。</li><li><code>Streaming batch shadow downgraded</code>：慢 batch 或 patch 导致 shadow trust 降级。</li><li><code>Streaming card perf summary</code> / <code>perf.card.lifecycle</code>：单张流式卡片生命周期汇总。</li></ul><p><code>Streaming card perf summary</code> 建议重点看：</p><ul><li>基础：<code>streamKey</code>、<code>chatId</code>、<code>cardId</code>、<code>messageId</code>、<code>elapsedMs</code>。</li><li>首屏：<code>createCardMs</code>、<code>sendMessageMs</code>、<code>initialPayloadBytes</code>、<code>initialComponentCount</code>。</li><li>flush：<code>flushAttempts</code>、<code>flushSuccesses</code>、<code>flushFailures</code>、<code>flushTimeouts</code>、<code>flushQueuedCount</code>。</li><li>plan：<code>noopCount</code>、<code>batchUpdateCount</code>、<code>fullRefreshCount</code>、<code>fullRefreshReasons</code>。</li><li>API 汇总：按 target 记录 <code>count</code>、<code>timeoutCount</code>、<code>totalMs</code>、<code>maxMs</code>。</li><li>payload：<code>maxPayloadBytes</code>、<code>maxComponentCount</code>、<code>finalPayloadBytes</code>、<code>finalComponentCount</code>。</li><li>finalize：<code>finalizeWaitMs</code>、<code>settingsMs</code>、<code>finalUpdateMs</code>、<code>backgroundFinalize</code>。</li></ul>`,76))])}const b=o(i,[["render",s]]);export{g as __pageData,b as default};
